#include<bits/stdc++.h>
using namespace std;

int main(){
    int a,b,c,d;
    cin>>a>>b>>c>>d;
    int bei[10001]={0,0};
    bei[2]=1;
    bei[3]=1;
    for(int i=4;i<b;i++){
        bei[i]=bei[i-1]+bei[i-2];
    }
    int x=(c-(a*bei[b-2])-a)/(bei[b-1]-1);
    cout<<bei[d]*x+bei[d-1]*a+a-x;
}
